@module intervals  src=intervals.lua  loc=75  sha=e33b768  mode=namespace  self=intervals

# Shapes
  @shape  interval = { loPpq, hiPpq: number; loUuid, hiUuid: string? } -- nil uuid edge = open toward channel start/end  @ 5

# Imports
  @const util = 'util'  @ 6
      @invariant  pure, stateless; a set is `true` (whole chan) or a ppq-ascending, non-overlapping list  @ 4

# Module-level constants
  @const intervals = {}  @ 8
  @const MAX = 64  @ 11

# Public API (intervals.*)
  -- Construction
  @api intervals.seed(loPpq, hiPpq, loUuid, hiUuid)  @ 15-21
  @api intervals.merge(set)  @ 24-47
      @contract  coalesces edge-inclusive touching/overlapping intervals; returns `true` past MAX; input not mutated  @ 23
  -- Queries
  @api intervals.intersects(set, lo, hi)  @ 52-58
      @contract  edge-inclusive overlap of [lo, hi] against any interval; `true` set always intersects  @ 51
  -- Reload fold
  @api intervals.absorbSeeds(dirt, seeds, payloadChans)  @ 65-73
      -- Reload fold: a seeded chan narrows to the merge of its seeds; an unseeded payload chan
      -- (mm-internal writes -- dedup, collision backstop) still folds whole. See design/interval-dirt.md § phase 2.
      @contract  mutates+returns dirt; seeded chan -> merge(seeds[chan]), unseeded payload chan -> true  @ 64

# Uses (outbound edges)
  @use call    util.add  @ merge:29,41
  @use require util  @ 6

